#include <iostream>
#include <queue>

using namespace std;

class Solution {
public:
    int dequeue() {
        if (queue.empty()) return -1;
        int front = queue.front();
        queue.pop();
        return front;
    }

    queue<int> queue;
};

int main() {
    Solution s;
    cout << s.dequeue() << endl;
    cout << s.dequeue() << endl;
    return 0;
}

